import Foundation
import Metal
import XCTest

@testable import SmeltRuntime

final class SmeltMeshEncoderTests: XCTestCase {
    func testRealCheckpointCrossBlockMatchesPinnedTorchFP32Fixture() throws {
        guard let packagePath = ProcessInfo.processInfo.environment["SMELT_RIG_PACKAGE"] else {
            throw XCTSkip("SMELT_RIG_PACKAGE is not set")
        }
        guard MTLCreateSystemDefaultDevice() != nil else {
            throw XCTSkip("No Metal device available")
        }
        let artifact = try SmeltRigArtifact(path: packagePath, verify: true)
        let runtime = try SmeltMeshEncoder(artifact: artifact)
        let query = decode(queryBase64, count: 3 * 512)
        let data = decode(dataBase64, count: 5 * 512)
        let expected = decode(expectedBase64, count: 3 * 512)
        let actual = try runtime.crossBlock(query: query, data: data)
        XCTAssertEqual(actual.count, expected.count)
        XCTAssertTrue(actual.allSatisfy(\.isFinite))
        var maximumDifference: Float = 0
        var squaredError: Double = 0
        var squaredReference: Double = 0
        for index in actual.indices {
            let difference = actual[index] - expected[index]
            maximumDifference = max(maximumDifference, abs(difference))
            squaredError += Double(difference * difference)
            squaredReference += Double(expected[index] * expected[index])
        }
        let relativeL2 = sqrt(squaredError / squaredReference)
        XCTAssertLessThan(maximumDifference, 4e-4)
        XCTAssertLessThan(relativeL2, 2e-4)
    }

    func testReducedEntireMichelangeloGraphMatchesPinnedTorchFP32Fixture() throws {
        guard let packagePath = ProcessInfo.processInfo.environment["SMELT_RIG_PACKAGE"] else {
            throw XCTSkip("SMELT_RIG_PACKAGE is not set")
        }
        guard MTLCreateSystemDefaultDevice() != nil else {
            throw XCTSkip("No Metal device available")
        }
        let artifact = try SmeltRigArtifact(path: packagePath, verify: true)
        let runtime = try SmeltMeshEncoder(artifact: artifact)
        let query = decode(queryBase64, count: 3 * 512)
        let data = decode(dataBase64, count: 5 * 512)
        let expected = decode(meshEncoderFullExpectedBase64, count: 3 * 896)
        let actual = try runtime.encodeReduced(query: query, data: data)
        XCTAssertEqual(actual.count, expected.count)
        XCTAssertTrue(actual.allSatisfy(\.isFinite))
        var maximumDifference: Float = 0
        var squaredError: Double = 0
        var squaredReference: Double = 0
        for index in actual.indices {
            let difference = actual[index] - expected[index]
            maximumDifference = max(maximumDifference, abs(difference))
            squaredError += Double(difference * difference)
            squaredReference += Double(expected[index] * expected[index])
        }
        let relativeL2 = sqrt(squaredError / squaredReference)
        XCTAssertLessThan(maximumDifference, 2e-3)
        XCTAssertLessThan(relativeL2, 5e-4)
    }

    func testProductionShapeMichelangeloSmoke() throws {
        guard ProcessInfo.processInfo.environment["SMELT_RIG_FULL_SMOKE"] == "1" else {
            throw XCTSkip("SMELT_RIG_FULL_SMOKE is not enabled")
        }
        guard let packagePath = ProcessInfo.processInfo.environment["SMELT_RIG_PACKAGE"] else {
            throw XCTSkip("SMELT_RIG_PACKAGE is not set")
        }
        guard MTLCreateSystemDefaultDevice() != nil else {
            throw XCTSkip("No Metal device available")
        }
        var points = [Float](repeating: 0, count: 54_000 * 6)
        for index in 0..<54_000 {
            points[index * 6] = Float((index * 37) % 4_096 - 2_048) / 2_048
            points[index * 6 + 1] = Float((index * 109) % 8_192 - 4_096) / 4_096
            points[index * 6 + 2] = Float((index * 251) % 16_384 - 8_192) / 8_192
            points[index * 6 + 3] = Float((index * 13) % 256 - 128) / 128
            points[index * 6 + 4] = Float((index * 29) % 256 - 128) / 128
            points[index * 6 + 5] = Float((index * 61) % 256 - 128) / 128
        }
        let artifact = try SmeltRigArtifact(path: packagePath, verify: true)
        let runtime = try SmeltMeshEncoder(artifact: artifact)
        let result = try runtime.encode(pointNormals: points)
        XCTAssertEqual(result.selectedSourceIndices.count, 512)
        XCTAssertEqual(result.embeddings.count, 512 * 896)
        XCTAssertTrue(result.embeddings.allSatisfy(\.isFinite))
        XCTAssertGreaterThan(result.embeddings.map(abs).max() ?? 0, 0.1)
    }

    private func decode(_ encoded: String, count: Int) -> [Float] {
        guard let data = Data(base64Encoded: encoded), data.count == count * 4 else {
            XCTFail("corrupt mesh-encoder fixture")
            return []
        }
        return data.withUnsafeBytes { bytes in
            (0..<count).map { index in
                Float(
                    bitPattern: bytes.loadUnaligned(
                        fromByteOffset: index * 4,
                        as: UInt32.self
                    ).littleEndian
                )
            }
        }
    }

    // PyTorch 2.11 CPU FP32 fixture, canonical checkpoint SHA-256
    // f4e4706a11cfb520cdde65156a0358545e4fbf8f36237aca01ea5e79d5cb5692.
    private let queryBase64 =
        ""
    private let dataBase64 =
        ""
    private let expectedBase64 =
        ""
}
